#[test]
fn highlight_html_wraps_in_colored_output() {
    let result = highlight_code("<div class=\"foo\">hello</div>", "html");
    assert!(result.contains("hello"));
    assert!(result.contains("div"));
}

#[test]
fn highlight_css_wraps_in_colored_output() {
    let result = highlight_code("body { color: red; }", "css");
    assert!(result.contains("body"));
    assert!(result.contains("color"));
}

#[test]
fn highlight_js_wraps_in_colored_output() {
    let result = highlight_code("const x = 1;", "js");

        assert!(result.contains("const"));
        assert!(result.contains("x"));
    }

    #[test]
    fn highlight_typescript_wraps_in_colored_output() {
        let result = highlight_code("const x: number = 1;", "typescript");
        assert!(result.contains("const"));
    }

    #[test]
    fn highlight_generic_returns_unchanged() {
        let code = "some random code without known language";
        let result = highlight_code(code, "unknown");
        assert_eq!(result, code);
    }

    #[test]
    fn highlight_empty_string() {
        let result = highlight_code("", "html");
        assert_eq!(result, "");
    }
}

use anyhow::{anyhow, Context, Result};
use async_trait::async_trait;
use serde::Deserialize;
use serde_json::json;

use super::tools::{ToolCall, ToolResponse, ToolSpec};
use super::{Provider, ProviderBackend};

#[derive(Debug, Clone, Default)]
pub(crate) struct AnthropicUsage {
    pub input_tokens: u32,
    pub output_tokens: u32,
    pub cache_creation_input_tokens: u32,
    pub cache_read_input_tokens: u32,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicResponse {
    pub content: Option<Vec<AnthropicContentBlock>>,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicContentBlock {
    pub text: Option<String>,
    #[serde(rename = "type")]
    #[serde(default)]
    pub block_type: Option<String>,
    #[serde(default)]
    pub id: Option<String>,
    #[serde(default)]
    pub name: Option<String>,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicStreamChunk {
    #[serde(rename = "type")]
    pub chunk_type: Option<String>,
    pub delta: Option<AnthropicDelta>,
    pub content_block: Option<AnthropicContentBlock>,
    pub index: Option<u32>,
    #[serde(default)]
    pub usage: Option<AnthropicStreamUsage>,
    #[serde(default)]
    pub message: Option<AnthropicStreamMessage>,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicStreamUsage {
    pub input_tokens: Option<u32>,
    pub output_tokens: Option<u32>,
    #[serde(default)]
    pub cache_creation_input_tokens: Option<u32>,
    #[serde(default)]
    pub cache_read_input_tokens: Option<u32>,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicStreamMessage {
    pub usage: Option<AnthropicStreamUsage>,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicDelta {
    pub text: Option<String>,
    #[serde(rename = "type")]
    #[serde(default)]
    pub delta_type: Option<String>,
    #[serde(default)]
    pub partial_json: Option<String>,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicModelsResponse {
    pub data: Option<Vec<AnthropicModelEntry>>,
}

#[derive(Debug, Deserialize)]
pub struct AnthropicModelEntry {
    pub id: Option<String>,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn anthropic_usage_default() {
        let usage = AnthropicUsage::default();
        assert_eq!(usage.input_tokens, 0);
        assert_eq!(usage.output_tokens, 0);
