        };
        let v = spec.to_openai_tool();
        assert_eq!(v["type"], "function");
        assert_eq!(v["function"]["name"], "test_tool");
        assert_eq!(v["function"]["description"], "a test");

    assert!(v["function"]["parameters"].is_object());
}

